const WORKFLOW_IMG_B64 = '';

function initWorkflowModal() {
  if (document.getElementById('workflowModal')) return;

  const overlay = document.createElement('div');
  overlay.id = 'workflowModal';
  overlay.style.cssText = [
    'display:none','position:fixed','inset:0','z-index:9999',
    'background:rgba(10,20,40,.72)','backdrop-filter:blur(4px)',
    'align-items:center','justify-content:center'
  ].join(';');

  overlay.addEventListener('click', e => {
    if (e.target === overlay) closeWorkflowModal();
  });

  const box = document.createElement('div');
  box.style.cssText = [
    'background:#fff','border-radius:14px','overflow:hidden',
    'box-shadow:0 24px 80px rgba(0,0,0,.4)',
    'max-width:92vw','display:flex','flex-direction:column'
  ].join(';');
  box.style.animation = 'wfSlideIn .22s cubic-bezier(.4,0,.2,1)';

  // Header
  const header = document.createElement('div');
  header.style.cssText = [
    'display:flex','align-items:center','justify-content:space-between',
    'padding:14px 20px 12px','border-bottom:1px solid #e2e8f0',
    'background:var(--navy,#1a3a5c)'
  ].join(';');
  header.innerHTML = `
    <div style="display:flex;align-items:center;gap:10px">
      <span style="width:28px;height:28px;border-radius:50%;background:rgba(255,255,255,.15);display:flex;align-items:center;justify-content:center;font-size:14px;color:#fff;font-weight:700">ℹ</span>
      <div>
        <div style="font-size:14px;font-weight:700;color:#fff">Workflow – Gestion de la charge</div>
        <div style="font-size:11px;color:rgba(255,255,255,.6);margin-top:1px">EQOS Energie · Atlantique Etudes</div>
      </div>
    </div>
    <button onclick="closeWorkflowModal()" style="background:rgba(255,255,255,.12);border:none;cursor:pointer;width:30px;height:30px;border-radius:6px;color:#fff;font-size:20px;display:flex;align-items:center;justify-content:center;"
      onmouseover="this.style.background='rgba(255,255,255,.25)'"
      onmouseout="this.style.background='rgba(255,255,255,.12)'"
    >×</button>
  `;

  // Image
  const imgWrap = document.createElement('div');
  imgWrap.style.cssText = 'padding:20px;background:#f8fafc;';

  const img = document.createElement('img');
  img.src = 'data:image/png;base64,' + WORKFLOW_IMG_B64;
  img.alt = 'Workflow Gestion de la charge';
  img.draggable = false;
  img.style.cssText = 'width:min(1060px,86vw);height:auto;display:block;border-radius:6px;';

  imgWrap.appendChild(img);
  box.appendChild(header);
  box.appendChild(imgWrap);
  overlay.appendChild(box);

  // Animation keyframe
  const style = document.createElement('style');
  style.textContent = '@keyframes wfSlideIn{from{opacity:0;transform:translateY(18px) scale(.97)}to{opacity:1;transform:translateY(0) scale(1)}}';
  document.head.appendChild(style);

  document.body.appendChild(overlay);
}

function openWorkflowModal() {
  initWorkflowModal();
  document.getElementById('workflowModal').style.display = 'flex';
}

function closeWorkflowModal() {
  const modal = document.getElementById('workflowModal');
  if (modal) modal.style.display = 'none';
}

document.addEventListener('keydown', e => {
  if (e.key === 'Escape') closeWorkflowModal();
});
